#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,mod=1e9+9;

int t,n,fac[N],inv[N],p[N];
bool b[N];

int quick_mi(int a,int b){
    long long ans=1,base=a;
    while(b>0){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int main(){
    fac[0]=1;
    for(int i=1;i<N;i++)
        fac[i]=1LL*fac[i-1]*i%mod;
    inv[N-1]=quick_mi(fac[N-1],mod-2);
    for(int i=N-2;i>=0;i--)
        inv[i]=1LL*inv[i+1]*(i+1)%mod;
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            scanf("%d",&p[i]);
            b[i]=0;
        }
        int ans=1,sum=0;
        for(int i=1;i<=n;i++)
            if(!b[i]){
                int cnt=0,j=i;
                while(!b[j])
                    b[j]=1,cnt++,j=p[j];
                //printf("cnt: %d\n",cnt);
                sum+=cnt-1;
                ans=1LL*ans*quick_mi(cnt,cnt-2)%mod*inv[cnt-1]%mod;
            }
        printf("%d\n",1LL*ans*fac[sum]%mod);
    }
    return 0;
}
